function traCuu() {
  let sbd = document.getElementById("sbd").value;
  let kq = document.getElementById("ketqua");

  if (data[sbd]) {
    let hs = data[sbd];
    kq.innerHTML = `Họ và tên: ${hs.ten} <br>
                    Ngày sinh: ${hs.ns} <br>
		    Lớp: ${hs.lop} <br><br>
                    Toán: ${hs.toan} <br>
                    Văn: ${hs.van} <br>
                    Anh: ${hs.anh} <br>
		    GDCD: ${hs.gdcd} <br>
		    CNghệ: ${hs.cn} <br>
		    Tin: ${hs.tin} <br>
		    KHTN: ${hs.khtn} <br>
		    LS&ĐL: ${hs.lsdl} <br>`;
  } else {
    kq.innerHTML = "Không tìm thấy!";
  }
}